// src/pages/Login.js
import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";

export default function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showError, setShowError] = useState(false);
  const [loading, setLoading] = useState(false);

  const onSubmit = async (e) => {
    e.preventDefault();
    setShowError(false);
    setLoading(true);
    try {
      // TODO: replace this demo with your real API call
      await new Promise((r) => setTimeout(r, 500));
      const ok = email === "admin@gmail.com" && password === "admin";
      if (ok) {
        navigate("/dashboard", { replace: true });
      } else {
        setShowError(true);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="g-auth-bg">
      <div className="g-auth-card">
        {/* Brand row */}
        <div className="g-auth-logo">
          <span className="g-dot g-blue" />
          <span className="g-dot g-red" />
          <span className="g-dot g-yellow" />
          <span className="g-dot g-green" />
          <span className="g-brand">NeuroFleetX</span>
        </div>

        {/* Titles */}
        <h1 className="g-title">Sign in</h1>
        <p className="g-subtitle">Use your account</p>

        {/* Error message */}
        {showError && (
          <div className="g-error">Wrong credentials. Try again.</div>
        )}

        {/* Form */}
        <form className="g-form" onSubmit={onSubmit}>
          <div className="g-field">
            <input
              type="email"
              className="g-input"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              autoComplete="username"
              required
              autoFocus
            />
          </div>

          <div className="g-field">
            <input
              type="password"
              className="g-input"
              placeholder="Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              autoComplete="current-password"
              required
            />
          </div>

          <div className="g-actions">
            <button className="g-btn" type="submit" disabled={loading}>
              {loading ? "Signing in…" : "Sign in"}
            </button>
          </div>
        </form>

        {/* Helper links */}
        <div className="g-help">
          <a href="#" onClick={(e) => e.preventDefault()} style={{ marginRight: 18 }}>
            Forgot password?
          </a>
          <Link to="/signup">Sign up</Link>
        </div>
      </div>
    </div>
  );
}
